1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
11	type Step = { op: "quote"; items: Item[] };
12	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
13	
14	const itemPremium = (item: Item): number => {
15	  const basePremium = BASE_PREMIUM_BY_TYPE[item.type];
16	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
17	  return basePremium + firstInsuranceSurcharge;
18	};
19	
20	const quotePremium = (items: Item[]): number => {
21	  const itemsTotal = items.reduce((sum, item) => sum + itemPremium(item), 0);
22	  return itemsTotal + PROCESSING_FEE;
23	};
24	
25	type QuoteResult = { premium: number };
26	
27	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
28	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
29	  return { results };
30	};
